# --- 2. Model Download and Loading ---
def download_file(url, local_path):
    """Downloads a file from a URL to a local path."""
    if os.path.exists(local_path):
        print(f"File already exists: {local_path}. Skipping download.")
        return

    print(f"Downloading {url} to {local_path}...")
    try:
        response = requests.get(url, stream=True)
        response.raise_for_status() # Raise an HTTPError for bad responses (4xx or 5xx)
        total_size = int(response.headers.get('content-length', 0))
        block_size = 1024 # 1 KB

        with open(local_path, 'wb') as f:
            for data in tqdm(response.iter_content(block_size), total=total_size // block_size, unit='KB', desc="Downloading"):
                f.write(data)
        print("Download complete.")
    except requests.exceptions.RequestException as e:
        print(f"Error downloading file: {e}")
        exit()

def load_pretrained_model(model_url, local_path, num_classes, device):
    """Downloads, loads, and adapts a pre-trained model."""
    download_file(model_url, local_path)

    print(f"Loading model from {local_path}...")
    model = resnet18(weights=None) # Initialize model without pre-trained weights initially
    model.fc = nn.Linear(model.fc.in_features, num_classes) # Adapt the final layer

    # Load state_dict from the downloaded file
    state_dict = torch.load(local_path, map_location=device)

    # Remove 'fc' layer weights from state_dict if it's not needed (as we've replaced it)
    # This step is crucial if the downloaded checkpoint includes the original FC layer
    # and we want to avoid size mismatch errors when loading into our new FC layer.
    # We load the weights of the *pretrained* model, which might have 1000 output classes.
    # Our new model will have num_classes.
    if 'fc.weight' in state_dict:
        del state_dict['fc.weight']
    if 'fc.bias' in state_dict:
        del state_dict['fc.bias']

    # Load the remaining weights
    # strict=False allows to ignore keys that are not found in the model's state_dict
    # (e.g., the new fc layer we just added)
    model.load_state_dict(state_dict, strict=False)
    print("Pre-trained weights loaded successfully (excluding final FC layer).")

    # Move model to device
    model = model.to(device)

    return model

# --- 3. Custom Dataset and DataLoader (Example: CIFAR-10) ---
